import { useCallback, useState } from "react";
import type { SmartyAddress } from "@workspace/api-client/public";
import { useGetSmartyAutocomplete } from "@workspace/api-client/public";
import { AutoComplete, type Option } from "@workspace/ui";
import { getMockAddresses } from "./mock-addresses";

type AddressAutoCompleteProps = {
  accountSlug: string;
  value?: string; // Just the street address string
  onValueChange?: (fullAddress: SmartyAddress) => void;
  onInputChange?: (inputValue: string) => void;
  disabled?: boolean;
  placeholder?: string;
  className?: string;
  label: string;
  showRequired?: boolean;
  required?: boolean;
};

const formatAddressOption = (
  address: SmartyAddress,
  fullAddress = false,
): Option => {
  const parts = [
    address.street_line,
    address.secondary,
    address.city,
    address.state,
    address.zipcode,
  ].filter(Boolean);

  return {
    city: address.city || "",
    entries: address.entries?.toString() || "",
    label: fullAddress ? parts.join(", ") : address.street_line || "",
    secondary: address.secondary || "",
    state: address.state || "",
    street_line: address.street_line || "",
    value: JSON.stringify(address),
    zipcode: address.zipcode || "",
  };
};

const parseAddressOption = (option: Option): SmartyAddress => {
  try {
    return JSON.parse(option.value);
  } catch {
    // Fallback to reconstructing from option properties
    return {
      city: option.city,
      entries: option.entries ? Number.parseInt(option.entries, 10) : undefined,
      secondary: option.secondary,
      state: option.state,
      street_line: option.street_line,
      zipcode: option.zipcode,
    };
  }
};

export const AddressAutoComplete = ({
  accountSlug,
  value,
  onValueChange,
  onInputChange,
  disabled = false,
  placeholder,
  className,
  label,
  showRequired = true,
  required = true,
}: AddressAutoCompleteProps) => {
  const [searchTerm, setSearchTerm] = useState("");

  // Check if we're in development mode
  const isDev = import.meta.env.DEV;

  // Use mock data in development, real API in production
  const {
    suggestions: apiSuggestions,
    isLoading: apiLoading,
    error: apiError,
  } = useGetSmartyAutocomplete({
    accountSlug,
    enabled: !isDev,
    filter: { searchTerm },
  });

  // Get mock suggestions in development mode
  const mockSuggestions = isDev ? getMockAddresses(searchTerm) : [];

  // Use mock data if in dev mode and we have search term, otherwise use API data
  const suggestions =
    isDev && searchTerm.trim() ? mockSuggestions : apiSuggestions;

  const isLoading = isDev ? false : apiLoading;
  const error = isDev ? null : apiError;

  const options: Option[] = (suggestions || []).map(
    (suggestion: SmartyAddress) => formatAddressOption(suggestion, true),
  );

  const handleValueChange = useCallback(
    (option: Option) => {
      const address = parseAddressOption(option);
      onValueChange?.(address);
    },
    [onValueChange],
  );

  const handleInputChange = useCallback(
    (inputValue: string) => {
      setSearchTerm(inputValue);
      onInputChange?.(inputValue);
    },
    [onInputChange],
  );

  return (
    <div className={className}>
      <input
        aria-hidden="true"
        autoComplete="street-address"
        name="fake_street_address"
        style={{
          height: "0",
          left: "-9999px",
          opacity: "0",
          position: "absolute",
          top: "-9999px",
          width: "0",
        }}
        tabIndex={-1}
        type="text"
      />
      <AutoComplete
        disabled={disabled}
        emptyMessage={
          error
            ? "Error loading addresses. Please try again."
            : searchTerm
              ? "No addresses found. Please try a different search term."
              : "Start typing to search for addresses..."
        }
        isLoading={isLoading}
        label={label}
        onInputChange={handleInputChange}
        onValueChange={handleValueChange}
        options={options}
        placeholder={placeholder}
        required={required}
        showRequired={showRequired}
        value={value}
      />
    </div>
  );
};

